import{_ as a,v as o,f as t,i as r}from"./chunks/framework.jfF5glnW.js";const m=JSON.parse('{"title":"Week 2 | SolidWorks 草图与基础建模","description":"","frontmatter":{"title":"Week 2 | SolidWorks 草图与基础建模","date":"2026-03-10T00:00:00.000Z","tags":["课程周志","SolidWorks","3D建模"],"cover":"/code2real_blog/posts/week2/sigmma.jpg"},"headers":[],"relativePath":"posts/week2.md","filePath":"posts/week2.md"}'),s={name:"posts/week2.md"};function l(i,e,p,d,c,n){return o(),t("div",null,[...e[0]||(e[0]=[r('<p>第二周开始系统接触 SolidWorks。本周的重点是熟悉草图绘制、尺寸标注、几何约束以及基础特征生成的基本流程。</p><hr><img src="/code2real_blog/posts/week2/sigmma.jpg" alt="Week 2 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周主要围绕 SolidWorks 的基础建模逻辑展开。与单纯的形状堆砌不同，课程练习更强调草图的结构完整性与尺寸逻辑——通过约束与标注，使草图具备可调整、可复用的稳定性。</p><p>重点练习了二维草图建立、智能尺寸工具、水平/垂直等几何约束，以及拉伸凸台、拉伸切除等基础特征命令。这些内容构成后续复杂模型的前置依赖。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>从简单轮廓入手，比如带角度变化的支架结构。逐步理解参考线、尺寸关系以及草图完全定义的意义——开始关注线段间的逻辑联系，而非仅仅凭视觉判断图形是否“像”。</p><p>后续练习涉及层次更丰富的结构模型。通过多次特征叠加，明确了一个认知：三维建模并非靠单一命令完成，而是通过主体结构、局部细节、附加特征逐步累积建立。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>最突出的问题出现在草图稳定性。初学时，图形表面看似完整，实则约束不足——一旦修改某个尺寸，整体形状就发生意外变动，说明逻辑关系未真正确立。</p><p>另一个问题与建模顺序有关。容易在主体结构未定时就过早加入孔位、倒角或装饰细节，导致后续调整主体尺寸时局部特征需反复修改，徒增工作量。正确的习惯是先建主体骨架，再加修饰特征。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>对三维建模的理解从“绘制外形”转向“建立结构关系”。草图是否稳定、特征顺序是否合理，直接决定模型的完整性与修改效率。</p><p>第二周的收获不仅在于掌握了几个命令，更重要的是开始形成面向结构与逻辑的建模意识——先确定约束，再叠加特征，降低耦合。这为后续复杂机械零件练习奠定了基础。</p><hr><img src="/code2real_blog/posts/week2/1.png" alt="Week 2 image"><img src="/code2real_blog/posts/week2/2.png" alt="Week 2 image"><img src="/code2real_blog/posts/week2/3.png" alt="Week 2 image"><img src="/code2real_blog/posts/week2/4.png" alt="Week 2 image">',20)])])}const _=a(s,[["render",l]]);export{m as __pageData,_ as default};
